/* ==========================================================
   名称：神秘紫色魔法主题 v10.0
   样式作者：AI Generated
   版本：v10.0
   基于：复古macOS UI蓝（改1）@Junezz
   ========================================================== */

@import url("https://fontsapi.zeoseven.com/570/main/result.css");

body {
    font-family: "Fusion Pixel 12px Monospaced zh_hans";
    font-weight: normal;
    background: linear-gradient(180deg, #551a80 0%, #3a1265 10%, #2a0f52 22%, #1a0838 38%, #0d0320 55%, #070212 75%, #04010a 100%);
    min-height: 100vh;
    position: relative;
    overflow-x: hidden;
}

body::before {
    content: '';
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: 
        radial-gradient(circle at 10% 6%, rgba(245, 220, 255, 0.25) 0%, transparent 55%),
        radial-gradient(circle at 90% 94%, rgba(255, 238, 155, 0.2) 0%, transparent 55%),
        radial-gradient(circle at 46% 46%, rgba(230, 190, 250, 0.14) 0%, transparent 75%),
        radial-gradient(circle at 20% 80%, rgba(250, 220, 255, 0.16) 0%, transparent 65%),
        radial-gradient(circle at 80% 20%, rgba(235, 200, 250, 0.12) 0%, transparent 60%);
    pointer-events: none;
    z-index: -1;
    animation: mysticalAura 12s ease-in-out infinite;
}

@keyframes mysticalAura {
    0%, 100% { opacity: 1; }
    33% { opacity: 0.85; }
    66% { opacity: 0.92; }
}

body::after {
    content: '';
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background-image: 
        radial-gradient(3px 3px at 30px 40px, rgba(255, 255, 255, 0.9), transparent),
        radial-gradient(2px 2px at 65px 95px, rgba(255, 255, 255, 0.7), transparent),
        radial-gradient(1.5px 1.5px at 115px 55px, rgba(255, 255, 255, 0.95), transparent),
        radial-gradient(2.5px 2.5px at 185px 145px, rgba(255, 255, 255, 0.8), transparent),
        radial-gradient(1.5px 1.5px at 255px 105px, rgba(255, 255, 255, 0.92), transparent),
        radial-gradient(2px 2px at 325px 175px, rgba(255, 255, 255, 0.6), transparent),
        radial-gradient(1.5px 1.5px at 385px 85px, rgba(255, 255, 255, 0.85), transparent),
        radial-gradient(2.5px 2.5px at 455px 205px, rgba(255, 255, 255, 0.75), transparent),
        radial-gradient(1.5px 1.5px at 535px 115px, rgba(255, 255, 255, 0.9), transparent),
        radial-gradient(2px 2px at 615px 165px, rgba(255, 255, 255, 0.65), transparent),
        radial-gradient(3px 3px at 165px 235px, rgba(255, 238, 155, 0.75), transparent),
        radial-gradient(2px 2px at 415px 295px, rgba(255, 238, 155, 0.55), transparent),
        radial-gradient(1.5px 1.5px at 295px 365px, rgba(255, 238, 155, 0.65), transparent),
        radial-gradient(2px 2px at 100px 300px, rgba(210, 180, 255, 0.6), transparent),
        radial-gradient(1.5px 1.5px at 500px 320px, rgba(210, 180, 255, 0.5), transparent);
    background-size: 680px 340px;
    pointer-events: none;
    z-index: -1;
    animation: starFieldTwinkle 4.5s ease-in-out infinite;
}

@keyframes starFieldTwinkle {
    0%, 100% { opacity: 0.4; }
    50% { opacity: 1; }
}

code, textarea, #send_textarea, input, select, button, .text_pole, .font-family-reset {
  font-family: inherit;
}

:root {
    --mainFontSize: calc(var(--fontScale)* 16px);
    --avatar-base-width: 48px;
    --avatar-base-height: 48px;
    --topbarIconSize: calc(var(--mainFontSize)* 1.3);
    --genericRadius: 0px;
    --warning: #ff9a9a;
    --crimson70a: rgba(255, 235, 255, 0.8);
    --crimson-hover: color-mix(in srgb, var(--SmartThemeUnderlineColor), transparent 90%) !important;
    --standardIconSize: calc(var(--mainFontSize)* 1);
    --bottomFormIconSize: calc(var(--mainFontSize)* 1.5);
    --bottomFormBlockPadding: calc(var(--mainFontSize)/ 1.5);
    --scrollBarWidth: 3px;
    --pagePadding: calc(var(--scrollBarWidth) + 9px);
    --genericLineHeight: calc(var(--mainFontSize)* 1.9);
    --utilityColor: var(--black50a);
    --navBackgroundColor: var(--SmartThemeBlurTintColor);
    --buttonFill: rgb(255, 255, 255);
    --menuBackgroundColor: var(--navBackgroundColor);
    --accentColor: var(--SmartThemeUnderlineColor);
    --accentColorOverlay: color-mix(in srgb, var(--SmartThemeBorderColor), transparent 95%);
    --scrollBarColor: var(--SmartThemeUnderlineColor);
    --boxShadowSubtle: 2px 2px 0px var(--SmartThemeBorderColor);
    --boxShadowSubtleAlt: 2px 2px 0px var(--SmartThemeBorderColor);
    --goldBorder: linear-gradient(135deg, #ffd700, #ffed4a, #ffd700, #e6c800, #d4a437, #ffd700);
    --purpleGlow: rgba(200, 160, 255, 0.6);
    --magicPurple: #9b59b6;
    --deepPurple: #4a1d7a;
    --starGold: #ffd700;
    --moonGlow: rgba(255, 238, 155, 0.65);
}

.mesAvatarWrapper, .avatar {
  width: var(--avatar-base-width) !important;
  height: var(--avatar-base-height) !important;
}

#app {
    position: relative;
    border: none;
    border-radius: var(--genericRadius);
    background: transparent;
    box-shadow: none;
    min-height: 100vh;
    margin: 0px;
}

.chat-box {
  background-color: var(--chat_tint_color) !important;
}

.mes {
  display: flex;
  margin: 0px !important;
  padding-bottom: 0px !important;
  border: none;
  background-color: transparent !important;
}

.mes_block {
  display: flex;
  flex-direction: column;
  flex: 1 1 auto;
  padding-top: 8px;
  overflow: hidden;
}

.mes .mesAvatarWrapper {
  flex: 0 0 auto;
  display: flex;
  align-items: flex-start;
  position: relative;
  padding: 8px 8px 0 0px !important;
  pointer-events: auto;
}

.mes[is_user="true"] .mesAvatarWrapper {
  padding: 8px 0px 0 8px !important;
}

.mes .mesAvatarWrapper .avatar {
  border-radius: var(--genericRadius) !important;
  filter: drop-shadow(0px 0px 2px var(--buttonFill));
}

.last_mes .mesAvatarWrapper {
  padding-bottom: 16px !important;
}

.mes_block {
  padding-left: 8px;
}

.mes .ch_name {
  display: flex;
  flex-direction: row;
  align-items: baseline;
  gap: 8px;
  border-radius: var(--genericRadius);
  padding: 16px;
  margin-bottom: 8px;
  border-bottom: 1px solid var(--SmartThemeBorderColor);
}

.mes_block .ch_name .flex-container {
    min-width: 0;  
    flex: 1 1 auto;
}

body .mes[is_user="true"] .mes_block .ch_name, body .mes[is_user="true"] .mes_block .ch_name .flex-container {
  flex-direction: row-reverse;
}

.mes_text {
    padding: 0px 2px !important;
    line-height: var(--genericLineHeight);
}

.mes_text p {
  margin-bottom: 12px;
}

.last_mes .mesAvatarWrapper {
  padding-bottom: 5px !important;
}

.mes_block {
  padding-left: 0px !important;
}

.mes_edit_buttons {
  filter: drop-shadow(0px 0px 2px var(--buttonFill));
}

.mes_edit_buttons .menu_button, .mes_reasoning_actions .edit_button {
  color: var(--SmartThemeBodyColor);
}

.mes_text blockquote, .mes_reasoning blockquote {
  background-color: var(--accentColorOverlay);
  border-left: var(--accentColor) 2px solid;
  padding: 8px;
  margin-bottom: 8px;
}

.extensions_info .extension_disabled {
  color: var(--SmartThemeEmColor);
}

.menu_button  {
  filter: none !important;
  background-color: var(--buttonFill);
  box-shadow: var(--boxShadowSubtle);
}

.menu_button:hover {
  background-color: var(--crimson-hover) !important;
}

.integrated-button-row {
  background-color: var(--menuBackgroundColor) !important;
}

#top-bar, #send_form {
  background-color: color-mix(in srgb, var(--navBackgroundColor) 50%, transparent 50%) !important;
  padding: 6px 8px;
  border: 1px solid var(--SmartThemeBorderColor);
}

body.no-blur #top-bar, body.no-blur #send_form {
  background-color: var(--navBackgroundColor) !important;
  padding: 6px 8px;
}

#send_form, body.no-blur #send_form {
  border-radius: var(--genericRadius);
}

body #top-bar, body #send_form {
  box-shadow: none;
}

input[type='checkbox'] {
  background-color: var(--buttonFill);
  box-shadow: var(--boxShadowSubtle);
  border-radius: var(--genericRadius);
}

input[type="checkbox"]::before {
  box-shadow: inset 1em 1em var(--SmartThemeEmColor);
}

input[type="checkbox"]:disabled {
  background-color: color-mix(in srgb, var(--buttonFill) 20%, black 10%);
  opacity: 0.7;
}

#completion_prompt_manager_list {
  background-color: var(--menuBackgroundColor) !important;
  padding: 0px 8px;
  border: none !important;
  box-shadow: none !important;
}

#completion_prompt_manager .caution {
  color: var(--warning);
}

#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt {
  background-color: var(--buttonFill);
  border: 1px solid var(--SmartThemeBorderColor);
  border-radius: 2px;
  padding: 8px;
  margin-bottom: 8px;
}

#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt.completion_prompt_manager_prompt_disabled {
  background-color: var(--menuBackgroundColor) ;
  border: transparent;
  border-radius: 2px;
  padding: 8px;
  margin-bottom: 8px;
}

#completion_prompt_manager .completion_prompt_manager_header {
  color: var(--SmartThemeBodyColor);
}

.text_muted {
  color: var(--utilityColor);
}

#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt span span span,
.mes_button, #completion_prompt_manager .completion_prompt_manager_header_advanced span{
  filter: none !important;
}

#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name, #completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
  color: var(--utilityColor);
}

.mes_text q {
  color: var(--SmartThemeQuoteColor); 
  background-color: var(--accentColorOverlay);
  margin: 0px 6px 0px 3px;
  padding: 5px 4px;
  font-size: calc(var(--mainFontSize)* 0.98);
  box-shadow: inset -1.5px -1.5px 0px var(--SmartThemeQuoteColor);
}

code {
  background-color: var(--accentColorOverlay);
  color: var(--SmartThemeUnderlineColor);
  border: none;
  border-bottom: 1.5px dashed var(--SmartThemeUnderlineColor);
  border-radius: var(--genericRadius);
  font-size: calc(var(--mainFontSize)* 0.98);
  padding: 4px 3px;
}

.range-block-title {
  margin: 8px 0px;
  text-align: left;
}

hr {
  background-image: none;
  background-color: var(--SmartThemeUnderlineColor);
  margin: 12px 0px;
}

.range-block {
  margin-bottom: 8px;
}

.checkbox_label {
  margin: 2px 0px;
}

#result_info_text {
  color: var(--SmartThemeBodyColor);
}

.editable-slider-notification {
  top:10px;
}

select, .range-block-counter input, .text_pole, textarea, .neo-range-input {
  filter: none !important;
  background-color: var(--buttonFill) !important;
  border: 1px solid var(--SmartThemeBorderColor) !important;
  margin: 4px 0px !important;
  border-radius: var(--genericRadius);
  box-shadow: var(--boxShadowSubtle);
}

#send_textarea {
  background-color: transparent !important;
  font-size: calc(var(--mainFontSize) - 1px);
}

input.neo-range-slider[type="range"]::-webkit-slider-thumb {
  border-radius: var(--genericRadius) !important;
  width: 12px;
  height: 12px;
  border: none;
  box-shadow: none !important;
  background-color: var(--scrollBarColor) !important;
}

input.neo-range-slider[type="range"] {
  border-radius: var(--genericRadius) !important;
  box-shadow: none !important;
  background-color: var(--accentColor) !important;
  opacity: 0.7;
}

input.neo-range-slider[type="range"]:disabled::-webkit-slider-thumb {
  border-radius: var(--genericRadius) !important;
  width: 12px;
  height: 12px;
  border: none;
  box-shadow: none !important;
  background-color: var(--scrollBarColor) !important;
}

input.neo-range-slider[type="range"]:disabled {
  border-radius: var(--genericRadius) !important;
  box-shadow: none !important;
  background-color: var(--accentColor) !important;
  opacity: 0.3;
}

.neo-range-slider:hover, input[type="range"]:hover {
  filter: brightness(0.85);
}

.range-block-range input[type="range"]::-webkit-slider-thumb {
  border-radius: var(--genericRadius) !important;
  width: 12px;
  height: 12px;
  border: none;
  box-shadow: none;
  background-color: var(--scrollBarColor) !important;
}

.range-block-range input[type="range"] {
  border-radius: var(--genericRadius) !important;
  box-shadow: none;
  background-color: var(--accentColor) !important;
}

.range-block-range input[type="range"]:disabled::-webkit-slider-thumb {
  border-radius: var(--genericRadius) !important;
  width: 12px;
  height: 12px;
  border: none;
  box-shadow: none !important;
  background-color: var(--scrollBarColor) !important;
}

.range-block-range input[type="range"]:disabled {
  border-radius: var(--genericRadius) !important;
  box-shadow: none !important;
  background-color: var(--accentColor) !important;
  opacity: 0.3;
}

#userSettingsRowOne {
  margin: 8px 0px;
}

.mes_reasoning_header_title {
  padding-right: 16px;
}

#rm_print_characters_block {
  margin-top: 8px;
}

#ui_language_select {
  width: 6em !important;
}

#rm_print_characters_pagination {
  background-color: var(--menuBackgroundColor);
  border-radius: var(--genericRadius);
  padding: 8px;
  margin: 8px;
}

.avatar-container.selected {
  border: 2px solid var(--SmartThemeBorderColor);
  border-radius: var(--genericRadius);
  box-shadow: var(--boxShadowSubtle);
}

.avatar-container:hover {
  background-color: var(--white20a);
}

.add_avatar:hover {
  filter: drop-shadow(0px 0px 4px var(--accentColor));
}

.character_select.is_fav .ch_name, .group_select.is_fav .ch_name, .group_member.is_fav .ch_name {
  color: var(--SmartThemeUnderlineColor);
}

.character_select.is_fav .avatar {
  outline: 2px solid var(--accentColor);
}

.mes_reasoning_details .mes_reasoning_summary,
.mes_reasoning,
.reasoning_edit_textarea {
  margin-left: 16px !important;
  margin-right: 16px !important;
}

.reasoning_edit_textarea {
  width: 100% !important;
}

.mes_reasoning_header_block {
  margin-top: 8px;
  margin-bottom: 16px;
}

.mes_reasoning_header {
  border: 1px solid var(--accentColor);
  border-radius: var(--genericRadius);
  background-color: transparent;
  justify-content: center;
  letter-spacing: 0.5px;
  margin: 0px;
  transition: all 0.25s ease;
  cursor: pointer;
  box-shadow: var(--boxShadowSubtleAlt);
}

.mes_reasoning_header:hover {
  background-color: var(--crimson-hover);
}

.mes_reasoning_details .mes_reasoning_arrow {
  height: var(--mainFontSize)*0.9;
  width: var(--mainFontSize)*0.9;
}

.mes_reasoning {
  border-left: var(--SmartThemeUnderlineColor) solid 2px;
  color: var(--SmartThemeBodyColor);
}

::-webkit-scrollbar {
  width: var(--scrollBarWidth);
  height: var(--scrollBarWidth);
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb:vertical,
::-webkit-scrollbar-thumb:horizontal {
  border-radius: var(--genericRadius);
  background-color: var(--scrollBarColor);
  border: none;
  box-shadow: none;
}

.drawer-content .alignItemsBaseline {
  align-items: center !important;
}

.flex1.flex-container.alignItemsBaseline {
  min-width: 214px;
}

.fa-solid.fa-circle-question.note-link-span {
  padding-top: 5px;
  padding-bottom: 5px;
}

.doubleRangeContainer > .doubleRangeInputContainer::after {
  background-color: var(--SmartThemeEmColor);
  box-shadow: none !important;
}

div[is_user="false"].last_mes .mes_block {
  padding-bottom: 48px;
}

.swipes-counter {
  margin: 0px;
  min-width: max-content;
}

.flex-container.swipeRightBlock {
  display: flex;
  flex-direction: row-reverse;
  padding-bottom: 20px;
  margin-right: 16px;
}

.popup #qr--modalEditor #qr--modal-message {
  color: var(--SmartThemeBodyColor) !important;
  background-color: var(--buttonFill) !important;
}

.popup:has(#qr--modalEditor) .popup-content #qr--modal-message::selection {
  color: var(--SmartThemeBodyColor) !important;
}

#HotSwapWrapper > div {
  overflow: auto hidden;
  flex-wrap: nowrap;
  justify-content: flex-start;
  gap: 8px;
  min-height: calc(var(--avatar-base-height)* 1.5);
}

#HotSwapWrapper > div::-webkit-scrollbar-thumb {
  background-color: var(--scrollBarColor);
}

#HotSwapWrapper {
  overflow: hidden;
}

.mes_text table {
  width: 100%;
  border-collapse: collapse;
  margin: 8px 0;
  color: var(--SmartThemeQuoteColor);
  background-color: var(--accentColorOverlay);
  border-radius: var(--genericRadius);
  overflow: hidden;
  border: 1px solid var(--accentColor);
  box-shadow: var(--boxShadowSubtleAlt);
}

.mes_text th,
.mes_text td {
  border: none;
  border-right: 1px solid var(--accentColor);
  padding: 10px 14px;
  text-align: left;
  border-bottom: 1px solid var(--accentColor);
}

.mes_text th {
  font-weight: 700;
}

.mes_text tr:last-child td {
  border-bottom: none;
}

.mes_text tr:nth-child(even) {
  background-color: rgba(255, 255, 255, 0.025);
}

.mes_text td:last-child,
.mes_text th:last-child {
  border-right: none;
}

.mes_text pre {
  background-color: var(--accentColorOverlay);
  padding: 12px 14px;
  border-radius: var(--genericRadius);
  font-family: inherit;
  font-size: calc(var(--mainFontSize)* 0.95);
  letter-spacing: 0.3px;
  overflow-x: auto;
  white-space: pre-wrap;
  word-break: break-word;
  border-left: 2px solid var(--SmartThemeUnderlineColor);
  position: relative;
}

.mes_text pre code {
  line-height: var(--genericLineHeight);
}

.mes_text pre code {
  font-family: inherit;
  color: inherit;
  background: none;
  border: none;
}

#InstructSettingsColumn .text_pole,
#InstructSettingsColumn select,
#InstructSettingsColumn .menu_button,
#InstructSettingsColumn input[type='checkbox'] {
  background-color: var(--white30a) !important;
}

@media (max-width: 600px) {
  #rm_extensions_block {
    padding-right: 24px;
  }
  #bg_menu_content {
    width: 100%;
  }
  #character-script-list, #global-script-list, #saved_scoped_scripts, #saved_regex_scripts {
    flex-wrap: wrap !important;
    max-width: 75vw;
  }
  .regex-script-label, #global-script-list .script-item, #character-script-list .script-item {
    max-width: 75vw;
    flex-wrap: wrap;
    border-radius: var(--genericRadius) !important;
    background-color: var(--buttonFill) !important;
    gap: 4px !important;
    padding-top: 8px !important;
    padding-bottom: 4px !important;
    border: 1px solid var(--SmartThemeBorderColor) !important;
    box-shadow: var(--boxShadowSubtle) !important;
  }
  .regex-script-label > div:last-of-type,
  #global-script-list .script-item > div:last-of-type,
  #character-script-list .script-item > div:last-of-type {
    flex-basis: 100%;
    width: 100%;
  }
  .regex-script-label > div:first-of-type,
  #global-script-list .script-item > div:first-of-type,
  #character-script-list .script-item > div:first-of-type {
    flex: 1;
    min-width: 0;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }
  .regex-script-label > span,
  #global-script-list .script-item .drag-handle,
  #character-script-list .script-item .drag-handle {
    flex-shrink: 0;
  }
  .regex-script-label:has(.disable_regex:checked),
  #global-script-list .script-item:not(:has(.script-toggle.enabled)),
  #character-script-list .script-item:not(:has(.script-toggle.enabled)) {
    background-color: var(--accentColorOverlay) !important;
    border: none !important;
    border-left: 1.5px solid var(--SmartThemeUnderlineColor) !important;
    box-shadow: none !important;
  }
}

@supports (-webkit-touch-callout: none) {
  #chat {
    padding-right: var(--pagePadding);
  }
  .drawer-content:not(#left-nav-panel):not(#right-nav-panel) {
    max-width: 100dvw;
  }
  #world_popup {
    width: 100%;
  }
}

@supports (-webkit-touch-callout: none) {
  @media screen and (min-width: 768px) {
    #sheld {
      width: var(--sheldWidth);
      margin-left: auto;
      margin-right: auto;
    }
    #top-bar, #top-settings-holder .drawer .drawer-content {
      width: var(--sheldWidth);
    }
    #left-nav-panel,
    #right-nav-panel,
    #character_popup,
    #world_popup,
    .drawer-content {
      top: var(--topBarBlockSize);
    }
    #character_popup,
    #world_popup,
    .drawer-content {
      margin-top: 0px;
      top: var(--topBarBlockSize);
    }
  }
}

#settings-panel input, #settings-panel select, #settings-panel textarea,
#settings-panel2 input, #settings-panel2 select {
  color: var(--SmartThemeBodyColor) !important;
  background-color: var(--buttonFill) !important;
}

#quick-reply-rocket-button i {
  font-size: var(--bottomFormIconSize) !important;
  color: var(--SmartThemeUnderlineColor) !important;
}

#quick-reply-menu {
  border-radius: var(--genericRadius) !important;
  border: 1px solid var(--SmartThemeBorderColor) !important;
  background-color: var(--menuBackgroundColor) !important;
  box-shadow: var(--boxShadowSubtle) !important;
}

.quick-reply-list-title {
  color: var(--SmartThemeBodyColor) !important;
  border-bottom: 1px solid var(--accentColor) !important;
}

.quick-reply-list {
  border: 1px solid var(--accentColor) !important;
  border-radius: var(--genericRadius) !important;
}

.quick-reply-item {
  background-color: var(--buttonFill) !important;
  color: var(--SmartThemeBodyColor) !important;
  border-radius: var(--genericRadius) !important;
}

.quick-reply-item:hover {
  background-color: var(--crimson-hover) !important;
}

.form-group label {
